# -- UTILIDADES -------------------------------------------------------

def sf(x):
    return Integer(x).squarefree_part()

def C3(n, m):
    n, m = Integer(n), Integer(m)
    return n * (n - m) * (_sage_const_2 *n - m) * (_sage_const_3 *n - m)

def is_perfect_square(x):
    if x < _sage_const_0 :
        return False, Integer(_sage_const_0 )
    s = Integer(x).isqrt()
    return (s * s == x), s

def log_msg(msg, f=None, also_print=True):
    if also_print:
        print(msg)
    if f:
        f.write(msg + "\n")
        f.flush()

