def tabla_3_ratios(N, max_multiples, f):
    log_msg("\n" + "="*_sage_const_65 , f)
    log_msg("BLOQUE 1: Tabla 3 -- Ratios R = x/N para N = %d" % N, f)
    log_msg("="*_sage_const_65 , f)

    E = EllipticCurve(QQ, [_sage_const_0 , _sage_const_0 , _sage_const_0 , -Integer(N)**_sage_const_2 , _sage_const_0 ])
    rk = E.rank()
    log_msg("  E_%d: rango = %d" % (N, rk), f)
    if rk == _sage_const_0 :
        log_msg("  Rango 0: N=%d no es congruente." % N, f)
        return

    P = E.gens()[_sage_const_0 ]
    log_msg("  Generador P: x(P) = %.6f" % float(P[_sage_const_0 ]), f)
    log_msg("\n  %4s %20s %10s %10s" % ("n", "x(nP)", "R=x/N", "En (1,2)?"), f)
    log_msg("  " + "-"*_sage_const_50 , f)

    count_in_range = _sage_const_0 
    Q = P
    for k in range(_sage_const_1 , max_multiples + _sage_const_1 ):
        x = Q[_sage_const_0 ]
        R = QQ(x) / QQ(N)
        R_float = float(R)
        in_range = _sage_const_1p0  < R_float < _sage_const_2p0 
        if in_range:
            count_in_range += _sage_const_1 
        marker = "SI" if in_range else "NO"
        x_str = str(x)[:_sage_const_18 ]
        log_msg("  %4d %20s %10.4f %10s" % (k, x_str, R_float, marker), f)
        Q = Q + P

    pct = _sage_const_100p0  * count_in_range / max_multiples
    log_msg("\n  En rango (1,2): %d/%d (%.1f%%)" % (
        count_in_range, max_multiples, pct), f)

