# BLOQUE 2: TABLAS 7-8 -- Anchor Pairs
# Condicion: C3(n,m) = 4j^2 - 2jm  y  Delta = (4j-m)^2
# =====================================================================

def tabla_7_anchor_pairs(n_max, f):
    log_msg("\n" + "="*_sage_const_65 , f)
    log_msg("BLOQUE 2: Anchor Pairs -- n <= %d" % n_max, f)
    log_msg("  Condicion: C3(n,m) = 4j^2 - 2jm,  Delta = (4j-m)^2", f)
    log_msg("="*_sage_const_65 , f)

    pairs = []
    log_msg("  %3s %5s %5s %7s %14s %14s %10s %7s %7s" % (
        "#", "n", "m", "j", "C=C3(n,m)", "bj=4j^2-2jm",
        "Delta", "sqrt", "u/v"), f)
    log_msg("  " + "-"*_sage_const_80 , f)

    count = _sage_const_0 
    m_distribution = {}

    for n in range(_sage_const_2 , n_max + _sage_const_1 ):
        for m in range(_sage_const_1 , n):
            C = C3(n, m)
            if C <= _sage_const_0 :
                continue

            Delta = m*m + _sage_const_4 *C
            is_sq, s = is_perfect_square(Delta)
            if not is_sq:
                continue

            if (m + s) % _sage_const_4  != _sage_const_0 :
                continue

            j = (m + s) // _sage_const_4 
            if j <= _sage_const_0 :
                continue

            bj = _sage_const_4 *j*j - _sage_const_2 *j*m
            if bj != C:
                continue

            # Verificacion de traduccion: y = 4j - m debe ser sqrt(Delta)
            y_check = _sage_const_4 *j - m
            if y_check != s:
                log_msg("  ERROR traduccion: n=%d, m=%d" % (n, m), f)
                continue

            u = _sage_const_2 *n - m
            v = n
            uv = float(QQ(u) / QQ(v))

            count += _sage_const_1 
            pairs.append((n, m, j, int(C), int(bj), int(Delta), int(s), uv))
            m_distribution[m] = m_distribution.get(m, _sage_const_0 ) + _sage_const_1 

            log_msg("  %3d %5d %5d %7d %14d %14d %10d %7d %7.3f" % (
                count, n, m, j, C, bj, Delta, s, uv), f)

    log_msg("\n  Total anchor pairs encontrados: %d" % count, f)
    log_msg("  (Preprint reporta 24 para n <= 100)", f)

    log_msg("\n  Distribucion por m:", f)
    log_msg("  %5s %6s" % ("m", "count"), f)
    for m_val in sorted(m_distribution.keys()):
        log_msg("  %5d %6d" % (m_val, m_distribution[m_val]), f)
    log_msg("  Distintos valores de m: %d" % len(m_distribution), f)
    log_msg("  (Preprint reporta 19 valores de m)", f)

    return pairs, m_distribution

# =====================================================================
# BLOQUE 3: TABLAS 9-11 -- Puntos enteros en E_m y rangos estimados
# E_m: y^2 = m^2 + 4n(n-m)(2n-m)(3n-m)
# =====================================================================

def tabla_9_11_curvas_Em(m_values, x_bound, f):
    log_msg("\n" + "="*_sage_const_65 , f)
    log_msg("BLOQUE 3: Curvas E_m -- puntos enteros y rangos", f)
    log_msg("  Curva: y^2 = m^2 + 4n(n-m)(2n-m)(3n-m)", f)
    log_msg("  Busqueda: n in [1, %d]" % x_bound, f)
    log_msg("="*_sage_const_65 , f)

    rank_count = {_sage_const_2 : _sage_const_0 , _sage_const_3 : _sage_const_0 }
    total_points = _sage_const_0 
    all_curve_data = []

    for m in sorted(m_values):
        m = Integer(m)
        points = []

        for n in range(_sage_const_1 , x_bound + _sage_const_1 ):
            n_i = Integer(n)
            if n_i <= m:
                continue
            C = C3(n_i, m)
            if C <= _sage_const_0 :
                continue
            rhs = m*m + _sage_const_4 *C
            is_sq, s = is_perfect_square(rhs)
            if is_sq:
                points.append((int(n_i), int(s)))

        total_points += len(points)

        # Estimacion de rango por numero de puntos
        # Heuristica del preprint: k<=2 -> rango 0, k in [3,4] -> rango 1-2,
        # k in [5,10] -> rango >= 2, k > 10 -> rango >= 3
        k = len(points)
        if k <= _sage_const_2 :
            est_rank = _sage_const_2 
        elif k <= _sage_const_4 :
            est_rank = _sage_const_2 
        else:
            est_rank = _sage_const_3 

        if est_rank >= _sage_const_3 :
            rank_count[_sage_const_3 ] += _sage_const_1 
        else:
            rank_count[_sage_const_2 ] += _sage_const_1 

        pts_str = ", ".join(["(%d,%d)" % (nn, yy) for nn, yy in points[:_sage_const_4 ]])
        if len(points) > _sage_const_4 :
            pts_str += "..."

        log_msg("\n  E_%d: %d puntos, rango est. >= %d" % (
            int(m), len(points), est_rank), f)
        if points:
            log_msg("    Puntos (n,y): %s" % pts_str, f)

        all_curve_data.append((int(m), len(points), est_rank, points))

    total_curves = len(m_values)
    log_msg("\n  " + "="*_sage_const_40 , f)
    log_msg("  DISTRIBUCION DE RANGOS ESTIMADOS:", f)
    log_msg("  Rango = 2:  %d curvas (%.1f%%)" % (
        rank_count[_sage_const_2 ], _sage_const_100p0 *rank_count[_sage_const_2 ]/total_curves), f)
    log_msg("  Rango >= 3: %d curvas (%.1f%%)" % (
        rank_count[_sage_const_3 ], _sage_const_100p0 *rank_count[_sage_const_3 ]/total_curves), f)
    log_msg("  Total puntos enteros: %d" % total_points, f)
    log_msg("  (Preprint: 76 puntos, 57.9%% rango 2, 42.1%% rango >=3)", f)

    return all_curve_data

