# BLOQUE 4: TABLA 5 -- Orbita Mordell-Weil con regimen I/II/III
# =====================================================================

def clasificar_regimen(xP, N):
    xP_f = float(xP)
    N_f  = float(N)
    if xP_f < _sage_const_0 :
        return "I"
    elif N_f < xP_f < _sage_const_2p0 *N_f:
        return "II"
    else:
        return "III"

def tabla_5_mordell_weil(targets, max_k, f):
    log_msg("\n" + "="*_sage_const_65 , f)
    log_msg("BLOQUE 4: Tabla 5 -- Orbita Mordell-Weil completa", f)
    log_msg("  Targets: %s" % str(targets), f)
    log_msg("="*_sage_const_65 , f)

    log_msg("  %4s %4s %8s %5s %12s %10s %7s %6s %9s %6s" % (
        "N", "Reg", "h(P)", "k*", "x(k*P)", "m/n",
        "dig(n)", "sf_ok", "pred_dig", "err%"), f)
    log_msg("  " + "-"*_sage_const_80 , f)

    for N in targets:
        N = Integer(N)
        t0 = time.time()

        E = EllipticCurve(QQ, [_sage_const_0 , _sage_const_0 , _sage_const_0 , -N**_sage_const_2 , _sage_const_0 ])

        try:
            rk = E.rank(only_use_mwrank=True)
        except Exception:
            try:
                rk = E.rank()
            except Exception:
                log_msg("  %4d  rango no calculable" % int(N), f)
                continue

        if rk == _sage_const_0 :
            log_msg("  %4d  N no congruente (rango 0)" % int(N), f)
            continue

        try:
            P = E.gens()[_sage_const_0 ]
        except Exception as e:
            log_msg("  %4d  error generador: %s" % (int(N), str(e)), f)
            continue

        h_can   = float(E.height_pairing_matrix([P])[_sage_const_0 ][_sage_const_0 ])
        xP      = P[_sage_const_0 ]
        regimen = clasificar_regimen(xP, N)

        Q = P
        hallado = False
        kstar   = None
        xkP     = None

        for k in range(_sage_const_1 , max_k + _sage_const_1 ):
            xQ_f = float(Q[_sage_const_0 ])
            if float(N) < xQ_f < float(_sage_const_2 *N):
                kstar = k
                xkP   = Q[_sage_const_0 ]
                hallado = True
                break
            Q = Q + P

        if not hallado:
            log_msg("  %4d %4s %8.4f  k* no hallado en k<=%d" % (
                int(N), regimen, h_can, max_k), f)
            continue

        # Traduccion a (n, m) via Corolario 29
        ratio  = QQ(_sage_const_2 ) - QQ(xkP) / QQ(N)
        denom  = ratio.denominator()
        numer  = ratio.numerator()
        dig_n  = len(str(abs(denom)))

        C      = C3(denom, numer)
        sf_val = sf(C) if C > _sage_const_0  else Integer(-_sage_const_1 )
        sf_ok  = (sf_val == N)

        pred_dig = h_can * kstar**_sage_const_2  / float(RR(_sage_const_10 ).log())
        err_pct  = abs(pred_dig - dig_n) / max(dig_n, _sage_const_1 ) * _sage_const_100p0 

        log_msg("  %4d %4s %8.4f %5d %12.4f %10.6f %7d %6s %9.1f %6.2f%%" % (
            int(N), regimen, h_can, kstar,
            float(xkP), float(ratio),
            dig_n, str(sf_ok),
            pred_dig, err_pct), f)

        elapsed = time.time() - t0
        log_msg("    [%.1fs]" % elapsed, f, also_print=False)

