# BLOQUE 5: JERARQUIA SIEGEL
# Verifica: anchor pairs subset de puntos enteros de E_m
# =====================================================================

def verificar_jerarquia_siegel(pairs, curve_data, f):
    log_msg("\n" + "="*_sage_const_65 , f)
    log_msg("BLOQUE 5: Verificacion jerarquia Siegel", f)
    log_msg("  Anchor pairs subset {puntos enteros E_m, n>0, m<n}", f)
    log_msg("="*_sage_const_65 , f)

    siegel_index = {}
    for m, n_pts, est_rank, points in curve_data:
        siegel_index[m] = set((nn, yy) for nn, yy in points)

    ok_count   = _sage_const_0 
    fail_count = _sage_const_0 

    for n, m, j, C, bj, Delta, s, uv in pairs:
        m_int = int(m)
        n_int = int(n)
        y_anchor = s  # y = 4j - m = sqrt(Delta)

        in_siegel = (m_int in siegel_index and
                     (n_int, y_anchor) in siegel_index[m_int])

        if in_siegel:
            ok_count += _sage_const_1 
        else:
            fail_count += _sage_const_1 
            log_msg("  FALLO: anchor pair (n=%d,m=%d,j=%d) "
                    "no en puntos Siegel de E_%d" % (n, m, j, m), f)

    log_msg("\n  Anchor pairs en Siegel: %d/%d" % (
        ok_count, ok_count + fail_count), f)

    if fail_count == _sage_const_0 :
        log_msg("  OK: jerarquia confirmada en rango de busqueda", f)
    else:
        log_msg("  AVISO: %d pares fuera de rango "
                "(aumentar X_BOUND_EM)" % fail_count, f)

