def tabla_6_formula_digitos(f):
    log_msg("\n" + "="*_sage_const_65 , f)
    log_msg("BLOQUE 6: Tabla 6 -- Validacion formula dig(n)", f)
    log_msg("  dig(n) aprox h(P) * (k*)^2 / log(10)", f)
    log_msg("="*_sage_const_65 , f)

    # Datos del preprint (Tabla 5 y 6)
    datos = [
        # (N,   h_P,     k*,  dig_n_obs)
        (_sage_const_6 ,    _sage_const_0p8886 ,   _sage_const_2 ,   _sage_const_2 ),
        (_sage_const_22 ,   _sage_const_4p2531 ,   _sage_const_8 ,   _sage_const_118 ),
        (_sage_const_29 ,   _sage_const_8p8437 ,   _sage_const_72 ,  _sage_const_19911 ),
        (_sage_const_37 ,   _sage_const_13p5654 ,  _sage_const_16 ,  None),
        (_sage_const_61 ,   _sage_const_16p6107 ,  _sage_const_4 ,   _sage_const_116 ),
    ]

    log_msg("  %4s %8s %5s %8s %8s %8s %8s" % (
        "N", "h(P)", "k*", "(k*)^2", "Pred", "Obs", "Error"), f)
    log_msg("  " + "-"*_sage_const_55 , f)

    for N, hP, ks, obs in datos:
        pred = hP * ks**_sage_const_2  / float(RR(_sage_const_10 ).log())
        if obs is not None:
            err     = abs(pred - obs) / obs * _sage_const_100p0 
            err_str = "%.2f%%" % err
            obs_str = str(obs)
        else:
            err_str = "N/A"
            obs_str = "~300"
        log_msg("  %4d %8.4f %5d %8d %8.1f %8s %8s" % (
            N, hP, ks, ks**_sage_const_2 , pred, obs_str, err_str), f)

